CREATE DATABASE School;
USE School;

CREATE TABLE students(
	student_id SERIAL PRIMARY KEY,
	name VARCHAR(100) NOT NULL,
	age INT,
	gender VARCHAR(10),
	department VARCHAR(50),
	semester INT,
	gpa NUMERIC(3,2),
	email VARCHAR(100),
	phone VARCHAR(15),
	enrollment_date DATE,
	city VARCHAR(50)
);


SELECT * FROM students;
